 1	import React, { FC } from 'react';
 2	import { useNMStateTranslation } from 'src/utils/hooks/useNMStateTranslation';
 3	import { EnactmentStatuses } from 'src/views/policies/constants';
 4	
 5	import { RedExclamationCircleIcon } from '@openshift-console/dynamic-plugin-sdk';
 6	import { Button, ButtonVariant, Stack, StackItem } from '@patternfly/react-core';
 7	import { CheckIcon, CloseIcon, HourglassHalfIcon, InProgressIcon } from '@patternfly/react-icons';
 8	import { t_global_color_status_danger_200 as dangerColor } from '@patternfly/react-tokens/dist/js/t_global_color_status_danger_200';
 9	import { t_global_color_status_success_200 as successColor } from '@patternfly/react-tokens/dist/js/t_global_color_status_success_200';
10	import { V1beta1NodeNetworkConfigurationEnactment } from '@types';
11	
12	import { categorizeEnactments } from './utils';
13	
14	type NNCPStateColumnProps = {
15	  enactments: V1beta1NodeNetworkConfigurationEnactment[];
16	  onStateClick: (state: EnactmentStatuses) => void;
17	};
18	
19	const NNCPStateColumn: FC<NNCPStateColumnProps> = ({ enactments, onStateClick }) => {
20	  const { t } = useNMStateTranslation();
21	
22	  const { available, pending, failing, progressing, aborted } = categorizeEnactments(enactments);
23	
24	  const states = [
25	    {
26	      icon: <RedExclamationCircleIcon />,
27	      number: failing.length,
28	      label: EnactmentStatuses.Failing,
29	    },
30	    {
31	      icon: <CloseIcon color={dangerColor.value} />,
32	      number: aborted.length,
33	      label: EnactmentStatuses.Aborted,
34	    },
35	    {
36	      icon: <CheckIcon color={successColor.value} />,
37	      number: available.length,
38	      label: EnactmentStatuses.Available,
39	    },
40	    {
41	      icon: <InProgressIcon />,
42	      number: progressing.length,
43	      label: EnactmentStatuses.Progressing,
44	    },
45	    {
46	      icon: <HourglassHalfIcon />,
47	      number: pending.length,
48	      label: EnactmentStatuses.Pending,
49	    },
50	  ].filter((state) => state.number > 0);
51	
52	  return (
53	    <Stack hasGutter>
54	      {states.length === 0 && <StackItem>-</StackItem>}
55	      {states.map((state) => (
56	        <StackItem key={state.label}>
57	          <Button variant={ButtonVariant.link} isInline onClick={() => onStateClick(state.label)}>
58	            {state.icon} {state.number} {t(state.label)}
59	          </Button>
60	        </StackItem>
61	      ))}
62	    </Stack>
63	  );
64	};
65	
66	export default NNCPStateColumn;

